// CBT performance hardening layer for 900-student offline-first runs.
(function () {
  'use strict';

  const CFG = {
    studentRealtime: false,
    adminPollMs: 30000,
    adminCacheMs: 10000,
    syncMinMs: 60000,
    submitJitterMs: 600000,
    queueKey: 'CBT_FINAL_SUBMIT_QUEUE_V1',
    packagePrefix: 'CBT_STATIC_PACKAGE_',
    readinessId: 'cbt-offline-readiness'
  };

  window.CBT_ENABLE_STUDENT_REALTIME = false;
  window.CBT_PERFORMANCE_MODE = 'offline-first-900';

  const page = (location.pathname.split('/').pop() || 'index.html').toLowerCase();
  const isStudentPage = page === 'index.html' || page === '';
  const isExamPage = page === 'exam.html';
  const isAdminPage = page === 'admin.html';

  const sleep = ms => new Promise(resolve => setTimeout(resolve, ms));
  const jitter = max => Math.floor(Math.random() * max);

  function sendSW(type, data) {
    return new Promise(resolve => {
      if (!navigator.serviceWorker || !navigator.serviceWorker.controller) return resolve(null);
      const channel = new MessageChannel();
      const timer = setTimeout(() => resolve(null), 3000);
      channel.port1.onmessage = event => {
        clearTimeout(timer);
        resolve(event.data || null);
      };
      navigator.serviceWorker.controller.postMessage({ type, ...data }, [channel.port2]);
    });
  }

  function questionImages(questions) {
    const urls = [];
    const add = value => {
      if (!value || typeof value !== 'string') return;
      if (/^data:/i.test(value)) return;
      urls.push(value);
    };
    (questions || []).forEach(q => {
      add(q.gambar || q.image);
      if (Array.isArray(q.opsi)) q.opsi.forEach(o => add(o && (o.gambar || o.image)));
      const html = String(q.pertanyaan || q.soal || '');
      html.replace(/<img[^>]+src=["']([^"']+)["']/gi, (_, src) => add(src));
    });
    return [...new Set(urls)];
  }

  function scheduleVersion(config) {
    return String(config && (config.versi_soal || config.version || config.updated_at || config.mulai || 1));
  }

  function packageKey(examId, version) {
    return `${CFG.packagePrefix}${examId}_v${version}`;
  }

  async function cachePackage(examId, version, data) {
    if (!examId || !data || !Array.isArray(data.questions)) return false;
    const payload = {
      examId,
      version: String(version || 1),
      savedAt: Date.now(),
      questionCount: data.questions.length,
      imageCount: questionImages(data.questions).length,
      data
    };
    try {
      localStorage.setItem(packageKey(examId, version), JSON.stringify(payload));
    } catch (error) {
      console.warn('[CBTPerf] local package cache skipped:', error.message);
    }
    try {
      if (typeof window.cbtIdbSet === 'function') {
        await window.cbtIdbSet(packageKey(examId, version), payload);
      }
    } catch (error) {
      console.warn('[CBTPerf] idb package cache skipped:', error.message);
    }
    await sendSW('PRELOAD_URLS', { urls: questionImages(data.questions) });
    return true;
  }

  function patchCbtIdbSet() {
    if (typeof window.cbtIdbSet !== 'function' || window.cbtIdbSet.__cbtPerfPatched) return;
    const original = window.cbtIdbSet;
    window.cbtIdbSet = async function (key, value) {
      const result = await original.apply(this, arguments);
      try {
        if (String(key).startsWith('SOAL_') && value && Array.isArray(value.questions)) {
          const match = String(key).match(/^SOAL_(.+)_v(.+)$/);
          const examId = match ? match[1] : value.config && value.config.id_ujian;
          const version = match ? match[2] : scheduleVersion(value.config);
          await cachePackage(examId, version, value);
        }
      } catch (error) {
        console.warn('[CBTPerf] package hook failed:', error.message);
      }
      return result;
    };
    window.cbtIdbSet.__cbtPerfPatched = true;
  }

  function patchGasRun() {
    if (typeof window.gasRun !== 'function' || window.gasRun.__cbtPerfPatched) return;
    const original = window.gasRun;
    let lastSync = 0;
    let adminCache = null;

    window.gasRun = async function (action, ...args) {
      if (action === 'syncAnswers') {
        const now = Date.now();
        if (now - lastSync < CFG.syncMinMs && !(window.State && Number(State.timeRemaining || 0) <= 300)) {
          return { success: true, skipped: true, reason: 'sync-throttled' };
        }
        lastSync = now + jitter(15000);
      }

      if (action === 'getAdminMonitoringData' && typeof window.invokeSupabaseFunction === 'function') {
        const examId = args && args[1] ? String(args[1]) : '';
        const adminPass = sessionStorage.getItem('admin_pwd') || sessionStorage.getItem('adminPass') || localStorage.getItem('admin_pwd') || '';
        const summary = await window.invokeSupabaseFunction('admin_summary', { adminPass, examId, includePeserta: !args[0] }, 12000);
        if (summary && summary.success && summary.data && summary.data.success) return summary.data;
      }

      if (action === 'submitExam' && typeof window.invokeSupabaseFunction === 'function') {
        const timeUp = window.State && Number(State.timeRemaining || 0) <= 0;
        await sleep(jitter(timeUp ? CFG.submitJitterMs : 5000));
        const direct = await window.invokeSupabaseFunction('submit_exam', args[0], 20000);
        if (direct && direct.success && direct.data && direct.data.success) {
          dequeueSubmit(args[0]);
          return direct.data;
        }
        enqueueSubmit(args[0], direct && (direct.error || direct.status || direct.data && direct.data.error));
        return { success: true, queued: true, offlineSaved: true, score: args[0] && args[0].score || 0 };
      }

      if (isAdminPage && action === 'getAdminMonitoringData') {
        const now = Date.now();
        if (adminCache && now - adminCache.time < CFG.adminCacheMs) return adminCache.value;
        const value = await original.apply(this, arguments);
        adminCache = { time: now, value };
        return value;
      }

      return original.apply(this, arguments);
    };
    window.gasRun.__cbtPerfPatched = true;
  }

  function submitId(payload) {
    return payload && payload.examId && payload.user && payload.user.id ? `${payload.examId}_${payload.user.id}` : `submit_${Date.now()}`;
  }

  function readQueue() {
    try {
      const raw = localStorage.getItem(CFG.queueKey);
      const parsed = raw ? JSON.parse(raw) : [];
      return Array.isArray(parsed) ? parsed : [];
    } catch (error) {
      return [];
    }
  }

  function writeQueue(queue) {
    localStorage.setItem(CFG.queueKey, JSON.stringify(queue.slice(0, 1000)));
  }

  function enqueueSubmit(payload, reason) {
    if (!payload) return;
    const id = submitId(payload);
    const queue = readQueue().filter(item => item.id !== id);
    queue.push({ id, payload, reason: String(reason || 'pending'), attempts: 0, nextAt: Date.now() + 30000, createdAt: Date.now() });
    writeQueue(queue);
    console.warn('[CBTPerf] Submit queued for retry:', id, reason || '');
  }

  function dequeueSubmit(payloadOrId) {
    const id = typeof payloadOrId === 'string' ? payloadOrId : submitId(payloadOrId);
    writeQueue(readQueue().filter(item => item.id !== id));
  }

  async function drainSubmitQueue() {
    if (!navigator.onLine || typeof window.invokeSupabaseFunction !== 'function') return;
    const queue = readQueue();
    if (!queue.length) return;
    let changed = false;
    const now = Date.now();
    for (const item of queue) {
      if (item.nextAt && item.nextAt > now) continue;
      item.attempts = Number(item.attempts || 0) + 1;
      const res = await window.invokeSupabaseFunction('submit_exam', item.payload, 20000);
      if (res && res.success && res.data && res.data.success) {
        item.done = true;
        changed = true;
      } else {
        item.reason = String(res && (res.error || res.status || res.data && res.data.error) || 'retry-failed');
        item.nextAt = Date.now() + Math.min(15 * 60 * 1000, 30000 * Math.pow(2, Math.min(item.attempts, 5))) + jitter(30000);
        changed = true;
      }
    }
    if (changed) writeQueue(queue.filter(item => !item.done));
  }

  function optimizeImages(root) {
    (root || document).querySelectorAll('img').forEach(img => {
      img.loading = img.closest('.exam-page') ? 'eager' : 'lazy';
      img.decoding = 'async';
      if (!img.getAttribute('width') && !img.style.maxWidth) img.style.maxWidth = '100%';
    });
  }

  async function readinessStatus() {
    const state = window.State || {};
    const schedules = state.schedules || [];
    const localKeys = Object.keys(localStorage);
    const packageKeys = localKeys.filter(k => k.startsWith(CFG.packagePrefix));
    const soalKeys = localKeys.filter(k => k.startsWith('SOAL_'));
    const swStats = await sendSW('GET_CACHE_STATS', {});
    const storage = navigator.storage && navigator.storage.estimate ? await navigator.storage.estimate() : null;
    const appShellOk = !!(swStats && swStats.stats && Object.keys(swStats.stats).some(k => k.startsWith('cbt-app-')));
    const expected = schedules.length || soalKeys.length || packageKeys.length;
    const readyPackages = packageKeys.length || soalKeys.length;
    return {
      appShellOk,
      examPageOk: !!(swStats && JSON.stringify(swStats).includes('exam.html')),
      packageOk: expected === 0 ? readyPackages > 0 : readyPackages >= expected,
      imageCacheOk: !!(swStats && swStats.stats && Object.keys(swStats.stats).some(k => k.startsWith('cbt-images-'))),
      storageOk: !storage || !storage.quota || ((storage.quota - storage.usage) > 20 * 1024 * 1024),
      packageCount: readyPackages,
      queuedSubmits: readQueue().length,
      freeMb: storage && storage.quota ? Math.round((storage.quota - storage.usage) / 1024 / 1024) : null
    };
  }

  async function renderReadinessCard() {
    if (!isStudentPage) return;
    const syncPage = document.getElementById('mobile-sync-page');
    if (!syncPage) return;
    let card = document.getElementById(CFG.readinessId);
    if (!card) {
      card = document.createElement('div');
      card.id = CFG.readinessId;
      card.style.cssText = 'margin:14px 0;padding:12px;border:1px solid #e2e8f0;border-radius:12px;background:#fff;font-size:.78rem;color:#334155;line-height:1.5';
      syncPage.appendChild(card);
    }
    const s = await readinessStatus();
    const row = (ok, label) => `<div style="display:flex;justify-content:space-between;gap:10px;"><span>${label}</span><strong style="color:${ok ? '#059669' : '#d97706'}">${ok ? 'OK' : 'Cek'}</strong></div>`;
    card.innerHTML = [
      '<div style="font-weight:800;margin-bottom:6px;">Kesiapan offline</div>',
      row(s.appShellOk, 'Aplikasi tersimpan'),
      row(s.examPageOk, 'Halaman ujian tersimpan'),
      row(s.packageOk, `Paket soal (${s.packageCount})`),
      row(s.imageCacheOk, 'Cache gambar aktif'),
      row(s.queuedSubmits === 0, `Antrian submit (${s.queuedSubmits})`),
      row(s.storageOk, s.freeMb == null ? 'Ruang penyimpanan' : `Sisa ruang ${s.freeMb} MB`)
    ].join('');
  }

  function startAdminPolling() {
    if (!isAdminPage) return;
    setInterval(() => {
      if (document.hidden) return;
      const dash = document.getElementById('admin-dash-view');
      if (!dash || dash.style.display === 'none') return;
      if (typeof window._silentRefreshDashboard === 'function') {
        window._silentRefreshDashboard();
      } else if (typeof window.loadAdminDashboard === 'function') {
        window.loadAdminDashboard();
      }
    }, CFG.adminPollMs + jitter(5000));
  }

  function init() {
    patchCbtIdbSet();
    patchGasRun();
    optimizeImages(document);

    const observer = new MutationObserver(mutations => {
      mutations.forEach(m => m.addedNodes.forEach(node => {
        if (node.nodeType === 1) optimizeImages(node);
      }));
    });
    observer.observe(document.documentElement, { childList: true, subtree: true });

    if (isStudentPage) {
      setTimeout(renderReadinessCard, 1500);
      document.addEventListener('click', event => {
        if (event.target && event.target.closest('#btnSyncAllSoal,#btnRetrySyncAllSoal,#btnLanjutUtama')) {
          setTimeout(renderReadinessCard, 2000);
        }
      });
    }

    if (isExamPage && window.State && State.config && State.questions) {
      cachePackage(State.config.id_ujian, scheduleVersion(State.config), { config: State.config, questions: State.questions });
    }

    startAdminPolling();
    setInterval(drainSubmitQueue, 45000);
    window.addEventListener('online', () => setTimeout(drainSubmitQueue, 3000));
    setTimeout(drainSubmitQueue, 10000);
  }

  if (document.readyState === 'loading') document.addEventListener('DOMContentLoaded', init);
  else init();

  window.CBTPerformance = {
    cachePackage,
    readinessStatus,
    renderReadinessCard,
    optimizeImages
  };
})();
